const SOURCE = 'Floe career qualifications finance canonical bank'

// Canonical Qualifications: Finance subfamily (CFA Level I + CPA Exam).
// Consolidates the prior Finance/Finance2/Finance3 triplet. Every wrong answer
// carries a bespoke "why this is wrong" line (no DEFAULT_FLAW constants).
// Chapter names match the syllabi at src/data/syllabi/career/cfa_level_one.md
// and src/data/syllabi/career/cpa_exam.md.
function q(
  id: number,
  topic: Topic,
  chapter: string,
  title: string,
  prompt: string,
  correct: string,
  wrong: [string, string][], // [label, bespoke whyWrong]
  lesson: string,
): Question {
  return makeSimpleQuestion(
    id,
    topic,
    chapter,
    title,
    prompt,
    correct,
    wrong.map(([label, why]) => [label, why, lesson] as [string, string, string]),
    lesson,
    SOURCE,
  )
}

